-- Enrichment marathon batch: Codeberg's CI, Codecov (codecov.io), CodedThemes, CodeFactor, codehooks.io, CodeKeep, codemagic.io (Codemagic), Codename One (codenameone.com)

-- ── Codeberg's CI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codeberg's CI is the continuous integration service built into Codeberg, the German nonprofit's Forgejo-based Git hosting platform. It runs on Woodpecker CI, an open-source, container-based pipeline engine, and lets projects hosted on Codeberg automate testing, builds, and deployments. Access is free but gated by a manual approval process to protect shared infrastructure. Codeberg also offers Forgejo Actions, a GitHub-Actions-style alternative, in open alpha.$q$, short_description),
  pricing_model = COALESCE($q$Free, community-funded (no paid tiers; shared compute is rationed via manual approval and fair-use limits)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Volunteer-run nonprofit association (Codeberg e.V.), 1,300+ association members as of late 2025, small paid and volunteer operations team$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Codeberg CI Review 2026: Woodpecker CI for Codeberg$q$, seo_title),
  seo_meta_description = COALESCE($q$What Codeberg's CI is, how the free Woodpecker CI-based pipeline works, how to get access, its limits, and how it fits into Codeberg.org.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codeberg's CI is the continuous integration and continuous delivery service that Codeberg, the nonprofit German Git-hosting platform, provides to projects hosted on codeberg.org. Codeberg itself is operated by Codeberg e.V., a registered nonprofit association founded in September 2018 and headquartered in Berlin, Germany; the public Codeberg.org platform launched in January 2019 as a community-owned, donation- and membership-funded alternative to GitHub and GitLab, built on the open-source Forgejo software, a Gitea fork. Codeberg's CI is powered by Woodpecker CI, an open-source, container-native pipeline engine that grew out of the original Drone CI project after Drone's license changed; Codeberg runs a shared, publicly reachable Woodpecker instance at ci.codeberg.org. Because compute resources are limited and funded entirely by community memberships and donations, Codeberg does not open CI access to every repository automatically. Instead, maintainers must fill out a request form describing their use case; a Codeberg volunteer reviews the request and manually approves suitable projects to prevent abuse of shared infrastructure. Once approved, a user logs into ci.codeberg.org with their existing Codeberg account and enables CI for individual repositories from the Woodpecker repo-list page. Pipelines are defined in YAML files stored in the repository, and steps run inside Docker containers, similar to other container-based CI systems. Codeberg's shared runners only support the linux/amd64 architecture; teams that need other architectures, faster builds, or more predictable throughput are encouraged to attach their own self-hosted Woodpecker agents, which Woodpecker supports natively. Because the service is run by volunteers on donated infrastructure, Codeberg is explicit that CI access is provided on an as-is, best-effort basis and can be paused, rate-limited, or interrupted for maintenance without notice; there is no SLA. Role-based access control on the shared instance is also more limited than a typical commercial CI product, which can be a friction point for larger teams collaborating on a single repository. In parallel with Woodpecker CI, Codeberg has been rolling out Forgejo Actions, a CI system built directly into the Forgejo software Codeberg runs, using a syntax intentionally close to GitHub Actions; as of 2026 this remains in a limited open-alpha rollout alongside Woodpecker rather than a full replacement for it. There is no separate product page, sales team, or paid tier for Codeberg's CI, since it is a feature of the Codeberg platform itself rather than a standalone commercial product; the operation is funded by the roughly 1,300-plus paying members of Codeberg e.V. plus one-off donations, and governance is community-driven, with members electing the association's presidium and board. For directory and comparison purposes, Codeberg's CI is best understood as a free, ethically-run, resource-constrained alternative to commercial hosted CI/CD services such as GitHub Actions, GitLab CI, or CircleCI, aimed at open-source maintainers and small teams who value data sovereignty, European hosting, and a nonprofit governance model over guaranteed throughput or enterprise support. Typical users are open-source library maintainers, small self-hosted software projects, and privacy- or Europe-conscious developers moving away from large US-based platforms. It is not designed for, and does not attempt to compete with, high-volume commercial CI workloads that need guaranteed concurrency or dedicated support contracts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0f5c9c9d-b59e-41b9-8170-80aed2187fc8';

