-- ── CodedThemes ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CodedThemes is an Indian software vendor that designs and sells premium admin dashboard templates and UI kits for React, Angular, Vue, Bootstrap, Laravel, and CodeIgniter. Founded in 2017 and based in Surat, Gujarat, it operates a template marketplace with both free and paid products, with Able Pro, Berry, and Mantis as its best-known lines. Customers buy per-template licenses rather than a recurring platform subscription.$q$, short_description),
  pricing_model = COALESCE($q$One-time per-template licensing (Single Use, Extended Use, and Multi Extended Use license tiers), plus free templates$q$, pricing_model),
  starting_price = COALESCE($q$Free for free-tier templates; paid templates typically start in the tens of US dollars per license$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Roughly 10 to 40 employees$q$, company_size),
  headquarters = COALESCE($q$Surat, Gujarat, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CodedThemes Review 2026: Admin Templates and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$What CodedThemes sells, its Able Pro, Berry and Mantis template lines, license types, pricing structure, pros, cons and who should buy from it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CodedThemes is a template and UI-kit vendor founded in 2017 and headquartered in Surat, Gujarat, India, that designs and sells admin dashboard templates for web application front ends. Rather than being a SaaS platform with recurring subscriptions, CodedThemes operates more like a specialized digital marketplace: it builds a library of dashboard UI products once, in multiple front-end frameworks, and sells licenses to individual developers, agencies, and companies who use them as the starting point for internal tools, SaaS admin panels, CRMs, analytics dashboards, and other back-office interfaces. Its templates are built and maintained for the most common modern stacks, including React, Angular, Vue.js, and Bootstrap or plain HTML, as well as backend-oriented variants for Laravel and CodeIgniter, so a team can pick the same visual design system regardless of which framework their application uses. The company's flagship product lines are Able Pro, available across React, Angular, Vue, and Bootstrap versions and positioned as its premium, most fully featured dashboard, Berry, a widely downloaded template with both free and pro tiers and also available for CodeIgniter, and Mantis, a newer, lighter Material-UI-inspired dashboard offered in free and paid variants. Alongside dashboards, CodedThemes also publishes landing pages, admin UI component kits, and Figma design-system files, and it maintains a blog covering front-end and admin-UI topics. Commercially, CodedThemes departs from typical SaaS pricing: rather than monthly seats, it sells templates under one of three license types. A Single Use License covers one product for one non-commercial or internal end product where the end customer is not charged for access. An Extended Use License covers a single project where the end user of that project can be charged, for example a client-facing paid product, which is the license required for most commercial SaaS builds. A Multi Extended Use License covers unlimited projects where end users can be charged, aimed at agencies or software vendors that want to reuse the same template across many client engagements without buying a new license each time. Prices are quoted in US dollars, inclusive of tax, and vary by template and license tier, with free versions of several templates, such as Berry Free and Mantis Free, available as a way to trial the code quality before buying the pro version. Because CodedThemes is a template vendor rather than an infrastructure or SaaS company, it does not have uptime SLAs, API rate limits, or usage-based billing in the way a hosting or backend platform would; its main obligations to customers are template updates, documentation, and license enforcement. Support is typically handled through a ticketing system or marketplace channels, since it distributes some products through its own store and others via marketplaces such as Envato and ThemeForest. Typical buyers are individual freelance developers building admin panels quickly, startups and agencies that need a professional-looking back-office UI without a dedicated design team, and product teams standardizing on Able Pro, Berry, or Mantis as their internal design-system starting point. Competitors in this space include other template marketplaces and specific dashboard-kit vendors selling similar Bootstrap, React, and Vue admin themes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'faca7857-2bd8-451d-ac00-7dca0e45b289';

