-- ── codehooks.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$codehooks.io is a backend-as-a-service platform that lets developers write serverless JavaScript, TypeScript, or Node.js backend logic and deploy it in seconds via a CLI, with a built-in NoSQL document database, key-value store, queues with background workers, cron jobs, and webhook handling included behind every endpoint. It is built by Codehooks AS, a Norwegian company founded by the team behind restdb.io, and launched publicly in 2024 with flat-rate pricing instead of per-request metering.$q$, short_description),
  pricing_model = COALESCE($q$Flat-rate tiered subscription, not metered per request, with a free development tier and paid add-ons$q$, pricing_model),
  starting_price = COALESCE($q$Free (Development plan); paid plans start at $19 per month (Pro plan)$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Small team; exact headcount not publicly disclosed, spun out of the restdb.io team$q$, company_size),
  headquarters = COALESCE($q$Norway$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$codehooks.io Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$What codehooks.io does, its serverless JavaScript backend and NoSQL database, 2026 pricing tiers, key features, pros, cons and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$codehooks.io is a backend-as-a-service platform that lets developers write and deploy complete API backends using plain JavaScript, TypeScript, or Node.js, without managing servers, containers, or build pipelines. It is built and operated by Codehooks AS, a company based in Norway founded by Knut Martin Tornes and colleagues who previously built restdb.io, an online database backend launched in 2016; codehooks.io itself launched publicly in 2024 as an evolution of restdb.io's low-code hooks engine, rebuilt from scratch into a more complete, code-first backend platform aimed at JavaScript and TypeScript developers. The platform's central idea is that a single deployed codehooks.io project already includes everything most backends need out of the box: a queryable NoSQL document database built on RocksDB with a MongoDB-like query language, a separate lightweight key-value store, background job queues with dedicated workers, cron-scheduled tasks that can trigger behind any endpoint, REST API routing, static file hosting, and first-class inbound and outbound webhook handling with signature verification and automatic retries, useful for receiving events from services like Stripe, Shopify, or GitHub and forwarding processed results to end users. Authentication is handled through JWT and JWKS integration plus encrypted API keys, so teams can protect endpoints without standing up a separate auth service. codehooks.io is explicitly CLI-first: developers write handler functions locally, then deploy with a terminal command, with deploys typically completing in under five seconds because there are no containers to build or infrastructure to provision per deploy. The platform also markets itself as agent-ready, meaning it is designed to be driven by AI coding agents such as Claude Code or Cursor, which can write handler code and run the deploy command directly, and a webhook inspector tool lets developers capture, inspect, and replay incoming webhook payloads during development and debugging. Commercially, codehooks.io differentiates itself from most serverless platforms by using flat-rate, predictable pricing instead of per-request or per-invocation metering: a team's bill does not change based on how many webhooks it processes or how often it deploys, within its plan's rate limits. The Development plan is free and includes 60 API requests per minute, 150 megabytes of database storage, and one developer seat, suitable for prototyping and small personal projects. The Pro plan costs 19 US dollars per month and raises the ceiling to 3,600 API requests per minute, 15 gigabytes of database storage, and three developer seats. The Team plan costs 99 US dollars per month, with 6,000 API requests per minute, 25 gigabytes of database storage, and six developer seats. Beyond these tiers, teams can add capacity a la carte: additional developer seats cost 5 US dollars each, extra database storage is billed at 0.10 US dollars per gigabyte, file storage at 0.02 US dollars per gigabyte, custom domains at 10 US dollars, and dedicated spaces at 10 US dollars. Typical users are indie developers and small startups building an MVP API backend quickly, teams that need to reliably receive and process third-party webhooks from payment providers, e-commerce platforms, or CI systems, and developers who want a JavaScript-native alternative to heavier backend-as-a-service platforms like Firebase or Supabase for use cases centered on background jobs, cron automation, and webhook orchestration rather than a full relational database and auth suite.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b77ec0e4-dcb2-4ec6-b1b5-af439818971f';

