-- ── codemagic.io (Codemagic) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codemagic is a CI/CD platform purpose-built for mobile app development, supporting Flutter, React Native, iOS (Swift and Objective-C), and Android (Kotlin and Java) projects. It is developed by Nevercode, an Estonian company whose roots trace to a 2012 hackathon in Tartu, and Codemagic has an official partnership with Google as a recommended CI/CD tool for the Flutter ecosystem. It offers usage-based, fixed, and enterprise pricing built around macOS build minutes and concurrency.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with usage-based pay-as-you-go, fixed-price annual, and custom enterprise tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free (500 macOS M2 build minutes per month); pay-as-you-go from about $0.045 to $0.114 per build minute depending on machine type$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Team members across 15-plus countries; exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Tartu, Estonia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codemagic Review 2026: Pricing and Mobile CI/CD Features$q$, seo_title),
  seo_meta_description = COALESCE($q$What Codemagic does for Flutter, React Native, iOS and Android CI/CD, its 2026 pricing plans, key features, pros, cons and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codemagic is a continuous integration and continuous delivery platform built specifically for mobile application development, supporting Flutter, React Native, native iOS (Swift and Objective-C), and native Android (Kotlin and Java) projects. It is developed and operated by Nevercode, a company whose history traces back to 2012, when an internal hackathon at Mobi Lab, a development and design studio in Tartu, Estonia, produced a mobile-focused build tool originally called Greenhouse. Greenhouse shipped as a product in 2014 and the company rebranded to Nevercode in 2017 as a general mobile CI/CD service. In December 2018, at the Flutter Live event, Nevercode launched Codemagic as the first CI/CD tool built exclusively for Flutter applications, offering it free to everyone during its first several months before introducing paid pricing for professional developers and teams in May 2019. Codemagic has an official partnership with Google, under which it is promoted as a recommended CI/CD solution for Flutter developers, though Nevercode continues to operate Codemagic as its own company rather than as a Google-owned product; the company describes having team members across 15 or more countries. Codemagic's core workflow lets teams connect a mobile app repository, define a build pipeline through either a visual workflow editor or a codemagic.yaml configuration file, and run automated builds, tests, code signing, and store submissions across macOS, Linux, and Windows build machines, with results and artifacts, including IPA and APK files, delivered automatically to testers or app store review queues. Because iOS builds require macOS hardware, Codemagic's build-minute pricing is largely organized around which Mac machine tier a build runs on. As of 2026, Codemagic offers four main pricing structures for its core mobile CI/CD product. The Free plan provides 500 macOS M2 build minutes per month, refilled monthly, with one parallel build, one team member, 30-day build history, and community support. The Pay as You Go plan has no monthly base fee and instead charges per build minute: 0.095 US dollars per minute on a Mac mini M2, 0.114 US dollars per minute on a Mac mini M4, and 0.045 US dollars per minute on Linux or Windows machines, with additional concurrency available for 49 US dollars per month, app-preview builds billed at 0.095 US dollars per minute, unlimited team members, and 60-day artifact storage. Fixed Price plans trade usage-based billing for a flat annual fee with unlimited build minutes and three concurrent builds: 3,990 US dollars per year on the M2 plan, 5,400 US dollars per year on the M4 plan, and 9,000 US dollars per year on the M4 Max plan, with additional concurrency available for 1,500 to 3,000 US dollars per year depending on machine tier. The Enterprise plan starts at 12,000 US dollars per year and adds custom features, dedicated support, single sign-on via OpenID, OAuth2, or SAML 2.0, and signed SLAs, NDAs, and DPAs for regulated organizations. Codemagic separately prices its React Native CodePush over-the-air update service, either pay-as-you-go at 1 US dollar per 2,500 installs with no transfer or storage fees, or a fixed plan starting at 99 US dollars per month, billed per 100,000 monthly active users, with unlimited releases and included transfer and storage. Typical users are Flutter and React Native teams that need automated builds, testing, and code signing across both Apple and Google app stores, as well as native iOS and Android teams that want a mobile-specialized alternative to general-purpose CI providers like GitHub Actions, Bitrise, or CircleCI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fe10ef49-8462-4ceb-b099-a81501193e11';

