-- ── Codename One (codenameone.com) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codename One is an open-source, write-once-run-anywhere framework that lets Java and Kotlin developers build truly native mobile apps for iOS, Android, desktop, and web from a single codebase. It was founded in 2012 by Chen Fishbein and Shai Almog, former Sun Microsystems engineers who had previously created the LWUIT toolkit, and it compiles Java bytecode to native platform executables using cloud build servers. The core framework is free and open source, with optional paid cloud-build plans for higher quotas and advanced features.$q$, short_description),
  pricing_model = COALESCE($q$Open-source core framework (free) plus optional paid cloud build service tiers priced per developer seat$q$, pricing_model),
  starting_price = COALESCE($q$Free (100 build credits per month); paid plans start at $25 per month (Basic)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Small, founder-led team; exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codename One Review 2026: Pricing and Framework Features$q$, seo_title),
  seo_meta_description = COALESCE($q$What Codename One is, its Java and Kotlin cross-platform mobile framework, 2026 cloud build pricing, key features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codename One is an open-source, write-once-run-anywhere framework that lets developers build truly native applications for iOS, Android, desktop, web, and other platforms from a single Java or Kotlin codebase. It was founded in January 2012 by Chen Fishbein and Shai Almog, two engineers who had previously worked at Sun Microsystems, where in 2007 they created the Lightweight User Interface Toolkit, an open-source UI library aimed at simplifying Java ME mobile development. After leaving Oracle, which had acquired Sun, Fishbein and Almog founded Codename One as an independent, free alternative to proprietary cross-platform mobile tools, building on the component and abstraction ideas from LWUIT and adding a device simulator plus cloud-based build servers capable of compiling Java bytecode into native platform executables. The beta release in mid-2012 quickly passed 100,000 SDK downloads, reflecting demand at the time for tools that let Java developers reach iOS and Android without learning Objective-C or platform-specific Android tooling. Technically, Codename One combines a portable application runtime and UI toolkit with native compilers, per-platform ports, build tooling, and direct access to native SDK capabilities, allowing a single Java or Kotlin codebase to target iOS, Android, desktop operating systems, the web via a browser-based port, and other device categories, including TVs and wearables, without maintaining separate native codebases per platform. Because compiling native iOS binaries typically requires Apple's Xcode toolchain and macOS hardware, Codename One's cloud build service is central to its value proposition: it lets developers on Windows or Linux machines build native iOS apps without owning a Mac, by sending the project to Codename One's build servers. The core framework itself is fully open source and can be used commercially or non-commercially with no royalties, licensing fees, or per-app charges, which distinguishes it from some proprietary cross-platform tools that take a revenue cut or require enterprise contracts for commercial use. Codename One's commercial layer sits entirely around the optional cloud build service, which is priced per developer seat rather than per application. As of 2026, the Free plan includes 100 build credits per month, with an iOS cloud build consuming 8 credits and a maximum user JAR size of 8.5 megabytes, workable for evaluation and small projects. The Basic plan costs 25 US dollars per month, or 300 US dollars if billed annually, and unlocks unlimited build credits, access to native platform sources, a 50 megabyte build JAR size limit, 5,000 push notifications per month, 5 automated store submissions per month, two weeks of build versioning history, and in-app commerce validation up to 10,000 US dollars per month. The Pro plan costs 85 US dollars per month, or 1,020 US dollars annually, and adds concurrent cloud builds, GitHub Issues-integrated crash protection, 1 million push notifications per month, email support, native desktop app builds, 50 automated submissions per month, and commerce validation up to 200,000 US dollars per month. The Enterprise plan costs 450 US dollars per month, or 5,400 US dollars annually, and adds high-priority builds and CI, on-device unit testing, 10 million push notifications per month, phone support, unlimited automated submissions, and unlimited commerce validation. All paid plans carry a 30-day money-back guarantee. Codename One is typically chosen by teams and individual developers with existing Java or Kotlin expertise, including enterprise Java shops, who want to reach mobile and desktop platforms without adopting Swift, Kotlin Multiplatform-only tooling, Flutter and Dart, or React Native's JavaScript-centric stack, and by developers who specifically need to produce native iOS builds without owning Apple hardware.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ae5dbe6-de96-475d-8fa3-f54dcfab7a61';

