INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Woodpecker CI engine$q$, $q$Open-source, container-based pipeline runner hosted at ci.codeberg.org.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$In-repo YAML pipelines$q$, $q$Build and deploy steps are defined in YAML files stored alongside the code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Free shared runners$q$, $q$Approved projects get free access to shared linux/amd64 build capacity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Self-hosted agent support$q$, $q$Teams can attach their own Woodpecker agents for other architectures or dedicated throughput.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Forgejo Actions (alpha)$q$, $q$A GitHub-Actions-style CI system built into Forgejo, in limited open alpha.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Tight Forgejo integration$q$, $q$CI status is wired directly into Codeberg pull requests and repositories.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Community governance$q$, $q$Codeberg e.V. members elect the presidium and board overseeing the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Manual onboarding gate$q$, $q$New CI access requires a reviewed request form to protect shared resources.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Completely free to use once approved$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Open-source stack end to end across Forgejo and Woodpecker$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$No vendor lock-in and fully self-hostable if desired$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Supports self-hosted agents for specialized architecture or throughput needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Aligned with European data-sovereignty and nonprofit values$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Active development including the newer Forgejo Actions option$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Manual approval process adds delay before first use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$No SLA; the service can break or pause without notice$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Only linux/amd64 is supported on shared runners$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Limited role-based access control compared with commercial CI$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Not suited for heavy or high-concurrency commercial workloads$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$No dedicated support channel or enterprise tier$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Is Codeberg's CI free?$q$, $q$Yes. It is funded by Codeberg e.V.'s nonprofit memberships and donations, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$What CI engine does Codeberg use?$q$, $q$Woodpecker CI, an open-source, container-based pipeline engine, hosted at ci.codeberg.org.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$How do I get access to Codeberg's CI?$q$, $q$Fill out a request form describing your use case; a Codeberg volunteer manually reviews and approves it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Can I use my own build hardware with Codeberg's CI?$q$, $q$Yes, Woodpecker supports self-hosted agents that teams can attach for specialized needs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Does Codeberg's CI support architectures other than linux/amd64?$q$, $q$Not on the shared runners; other architectures require a self-hosted agent.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$What is Forgejo Actions and how does it relate to Woodpecker?$q$, $q$Forgejo Actions is a GitHub-Actions-style CI system built into Forgejo itself, currently in limited open alpha alongside Woodpecker.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Who operates Codeberg's CI?$q$, $q$Codeberg e.V., a German nonprofit association headquartered in Berlin, founded in 2018 with the platform launching in 2019.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Is there an SLA or guaranteed uptime for Codeberg's CI?$q$, $q$No. Access is provided on an as-is, best-effort basis with no guaranteed uptime.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Open-source test automation$q$, $q$Maintainers automate test suites and builds for public repositories at no cost.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Small team CI without vendor cost$q$, $q$Small development teams run CI pipelines without paying a commercial CI vendor.$q$, $q$Small development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$Moving CI off large US platforms$q$, $q$Privacy- and Europe-conscious developers shift CI workloads to nonprofit, European-hosted infrastructure.$q$, $q$Privacy-focused developers and organizations$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$how-codeberg-ci-works$q$, $q$How Codeberg's CI Works$q$, 2, ARRAY[$q$Codeberg's CI runs on Woodpecker CI, an open-source, container-native pipeline engine hosted at ci.codeberg.org. Pipelines are defined in YAML files stored directly in the repository, and each step runs inside a Docker container, an approach familiar to anyone who has used Drone CI, GitLab CI, or similar container-based systems.$q$, $q$Because Codeberg's compute is donated and limited, only linux/amd64 builds run on the shared instance. Projects needing other architectures, more throughput, or predictable performance can attach their own self-hosted Woodpecker agents, which plug into the same Codeberg-hosted control plane.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$access-and-limitations$q$, $q$Access, Limits, and Forgejo Actions$q$, 2, ARRAY[$q$Getting started requires filling out a request form; a Codeberg volunteer manually reviews and approves suitable use cases before granting access, a deliberate friction point meant to prevent abuse of shared resources funded by nonprofit memberships and donations.$q$, $q$Codeberg is upfront that the service has no SLA and can break or pause during maintenance. Role-based access control is also more limited than commercial CI products. In parallel, Codeberg has been rolling out Forgejo Actions, a GitHub-Actions-style CI system built into the Forgejo software itself, currently in limited open alpha alongside Woodpecker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', $q$who-its-for$q$, $q$Who Codeberg's CI Is For$q$, 2, ARRAY[$q$Codeberg's CI suits open-source maintainers, small self-hosted projects, and developers who prioritize European hosting and community governance over guaranteed uptime or enterprise support contracts.$q$, $q$It is not intended to compete with high-volume commercial CI platforms; teams with demanding concurrency or reliability needs are better served by paid providers or by attaching their own self-hosted Woodpecker agents to Codeberg's control plane.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0f5c9c9d-b59e-41b9-8170-80aed2187fc8', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Pull request coverage comments$q$, $q$Automated comments and status checks post directly on GitHub, GitLab, and Bitbucket pull requests.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Diff and patch coverage$q$, $q$Highlights exactly which new or changed lines in a pull request are untested.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Flags and components$q$, $q$Break coverage down by service, team, or test suite in large monorepos.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Carryforward flags$q$, $q$Prevents coverage numbers from falsely dropping when only part of a suite runs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Flaky test detection$q$, $q$Identifies tests that intermittently pass and fail to reduce noisy CI signals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Bundle analysis$q$, $q$Tracks JavaScript bundle size trends alongside test coverage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Broad CI and Git host integrations$q$, $q$Works with GitHub, GitLab, Bitbucket, CircleCI, Jenkins, Azure Pipelines, and more.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$API access$q$, $q$Programmatic access to coverage data for custom dashboards and reporting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Generous free tier for open-source and small private projects$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Deep, native pull-request integration reduces workflow friction$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Wide CI and language support via a simple uploader$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Historical trend graphs make coverage regressions easy to spot$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Enterprise options like SSO and dedicated cloud suit regulated teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Team plan is capped at 10 users, forcing a jump to Pro for growing teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Per-seat pricing can get expensive for large engineering organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Requires an existing test suite and coverage-report generation; it does not write tests itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Repeated ownership changes, from Sentry to Harness, create roadmap uncertainty$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Advanced features like components and bundle analysis add a learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Is Codecov free?$q$, $q$Yes, the Developer plan is free, with unlimited use for public open-source repositories.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$What coverage report formats does Codecov support?$q$, $q$Common formats including lcov, Cobertura XML, and JaCoCo, uploaded via CLI or GitHub Action.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Who owns Codecov now?$q$, $q$Harness, which acquired Codecov from Sentry in June 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Does Codecov run my tests for me?$q$, $q$No, it ingests coverage reports generated by your existing test runner during CI.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$What is the difference between the Team and Pro plans?$q$, $q$Team is capped at 10 users and 2,500 monthly private uploads for 5 dollars per user per month; Pro removes both caps for 12 dollars per user per month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Does Codecov support GitLab and Bitbucket, not just GitHub?$q$, $q$Yes, Codecov integrates with GitHub, GitLab, and Bitbucket.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$What are Codecov flags?$q$, $q$A way to tag coverage data by test suite, service, or component for more granular reporting.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Can Codecov block a pull request from merging?$q$, $q$Yes, via required status checks configured in the Git host based on Codecov's coverage results.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Open-source coverage tracking$q$, $q$Maintainers monitor public repository coverage and display badges for contributors.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Coverage-based merge gates$q$, $q$Teams require minimum coverage thresholds before pull requests can merge.$q$, $q$Mid-size engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Monorepo coverage governance$q$, $q$Enterprises track coverage across many services using flags and components.$q$, $q$Enterprise platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Developer$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["1 user, unlimited for open source","250 private-repo uploads per month","PR comments and status checks","API access, patch coverage, bundle analysis"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Team$q$, $q$$5 per user per month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 10 users","2500 private-repo uploads per month","Project coverage, flags, components","Flaky test detection, Sentry integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Pro$q$, $q$$12 per user per month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited users","Unlimited uploads","Everything in Team"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Dedicated cloud deployment","Okta SSO and IP allowlisting","Customer success manager","Dedicated onboarding and legal support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$what-is-codecov$q$, $q$How Codecov Works$q$, 2, ARRAY[$q$Codecov does not run tests itself; it ingests coverage reports produced by a team's existing test runner during a CI job, then visualizes that data as pull-request comments, status checks, diff coverage, and historical trend graphs.$q$, $q$It supports common coverage formats such as lcov, Cobertura XML, and JaCoCo, and connects via a lightweight uploader CLI or GitHub Action to nearly every major CI provider and Git host, including GitHub, GitLab, Bitbucket, CircleCI, Jenkins, and Azure Pipelines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$pricing-and-plans$q$, $q$Codecov Pricing Explained$q$, 2, ARRAY[$q$Codecov's pricing is per-seat: Developer is free with a 250-upload cap for private repos, Team is 5 US dollars per user per month for up to 10 users, and Pro is 12 US dollars per user per month with no user or upload cap.$q$, $q$Enterprise pricing is custom and adds a dedicated cloud option, Okta SSO, IP allowlisting, and dedicated onboarding and support for regulated or large organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d3384a3-5c53-49c6-8ec6-4333404223d5', $q$ownership-history$q$, $q$Ownership: Sentry to Harness$q$, 2, ARRAY[$q$Founded in 2015, Codecov was acquired by Sentry in November 2022 to pair coverage data with error monitoring, then acquired again by Harness in June 2026 to embed coverage intelligence into software delivery pipelines.$q$, $q$Despite two ownership changes, Codecov has retained its own product branding and self-serve pricing page, and continues to operate as a distinct product within its parent company.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Able Pro across four frameworks$q$, $q$Premium dashboard available in React, Angular, Vue, and Bootstrap versions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Berry template line$q$, $q$Free and pro tiers plus a dedicated CodeIgniter version.$q$, 1);
