INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Three-tier licensing model$q$, $q$Single Use, Extended Use, and Multi Extended Use licenses cover different commercial scenarios.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Free evaluation templates$q$, $q$Free versions let developers assess code quality before purchasing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Figma design-system files$q$, $q$Design files accompany coded templates for design-to-development workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Multi-framework design parity$q$, $q$The same visual design system is available across several front-end stacks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Documentation and updates$q$, $q$Licensed templates include documentation and ongoing update access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Multiple framework options under one consistent design language$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Free tiers let developers evaluate code quality before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$One-time license cost rather than a recurring subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Multi Extended Use License supports agencies reselling to many clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Established product lines with years of iteration behind them$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Licensing terms require care to pick correctly for commercial or SaaS use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$No platform-level SLA or hosting; it is code you must integrate and maintain yourself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Update cadence and long-term support vary by individual template$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Design language may need customization to differentiate from other buyers of the same template$q$, 3);
