INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$What does CodedThemes sell?$q$, $q$Admin dashboard templates and UI kits for multiple front-end frameworks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$What frameworks does CodedThemes support?$q$, $q$React, Angular, Vue, Bootstrap, Laravel, and CodeIgniter.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$What is Able Pro?$q$, $q$CodedThemes' flagship premium dashboard template line, available in four frameworks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Is there a free version of CodedThemes templates?$q$, $q$Yes, including Berry Free and Mantis Free.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$What license do I need for a SaaS product?$q$, $q$An Extended Use License for a single commercial project, or a Multi Extended Use License for multiple client projects.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Does CodedThemes charge a monthly subscription?$q$, $q$No, it sells one-time per-template licenses rather than recurring subscriptions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Where is CodedThemes based?$q$, $q$Surat, Gujarat, India, founded in 2017.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Can agencies resell CodedThemes templates to multiple clients?$q$, $q$Yes, with a Multi Extended Use License.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Fast internal admin panel$q$, $q$A startup builds an internal admin panel quickly using a pre-built template.$q$, $q$Startup engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Client SaaS dashboard delivery$q$, $q$An agency delivers a client-facing SaaS dashboard using a licensed template as the base.$q$, $q$Digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Freelance product prototyping$q$, $q$A freelance developer prototypes a paid product UI without designing from scratch.$q$, $q$Freelance and independent developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Single Use License$q$, $q$Varies by template$q$, $q$one-time$q$, NULL, $q$["Single non-commercial end product","End users not charged for access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Extended Use License$q$, $q$Varies by template$q$, $q$one-time$q$, NULL, $q$["Single commercial project","End users can be charged"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Multi Extended Use License$q$, $q$Varies by template$q$, $q$one-time$q$, NULL, $q$["Unlimited projects","Suited to agencies and SaaS resale"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$Free templates$q$, $q$Free$q$, $q$one-time$q$, NULL, $q$["Includes Berry Free and Mantis Free","Limited components versus pro versions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$product-lineup$q$, $q$Able Pro, Berry, and Mantis Template Lines$q$, 2, ARRAY[$q$Able Pro is CodedThemes' flagship premium dashboard, available in React, Angular, Vue, and Bootstrap versions, giving teams a consistent design system regardless of framework choice.$q$, $q$Berry is a widely downloaded template line with free and pro tiers plus a CodeIgniter version, while Mantis is a newer, lighter Material-UI-inspired dashboard also offered in both free and paid variants.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$licensing-explained$q$, $q$How CodedThemes Licensing Works$q$, 2, ARRAY[$q$CodedThemes sells one-time licenses rather than subscriptions. A Single Use License covers a single non-commercial product; an Extended Use License covers one commercial project where end users can be charged.$q$, $q$A Multi Extended Use License covers unlimited projects and is designed for agencies and SaaS vendors reusing the same template across many client engagements without buying repeat licenses.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('faca7857-2bd8-451d-ac00-7dca0e45b289', $q$who-buys-templates$q$, $q$Who Buys From CodedThemes$q$, 2, ARRAY[$q$Typical buyers include freelance developers building admin panels quickly, startups and agencies needing a polished back-office UI without a dedicated design team, and product teams standardizing on Able Pro, Berry, or Mantis.$q$, $q$Free versions such as Berry Free and Mantis Free let developers evaluate code quality before committing to a paid license.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Automatic PR and commit analysis$q$, $q$Every new commit and pull request is analyzed automatically with no configuration needed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$A-F letter grade scoring$q$, $q$Quality is summarized as a letter grade for files, directories, and repositories.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Historical grade trend charts$q$, $q$Tracks whether code quality is improving or declining over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Broad language support$q$, $q$Covers Python, JavaScript, TypeScript, Java, C#, Go, Swift, Kotlin, Dart, and 15-plus more languages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Autofix for select issues$q$, $q$Certain reported issues can be fixed on demand or automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Custom rule configuration$q$, $q$Teams can tailor rule sets and ignore findings judged not relevant.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$GitHub and Bitbucket integration$q$, $q$Zero-configuration connection to existing source control providers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Slack and Microsoft Teams notifications$q$, $q$Routes new quality issues into existing team chat workflows.$q$, 7);
