INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Exact Pro and Pro Max dollar pricing is not consistently published$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$What does CodeFactor's letter grade mean?$q$, $q$It is a composite score based on complexity, code duplication, style violations, and anti-patterns.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Is CodeFactor free?$q$, $q$Yes for unlimited public repositories and users; private repositories require a paid plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$How is CodeFactor priced?$q$, $q$Per private repository, not per user, unlike most code-quality competitors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$What languages does CodeFactor support?$q$, $q$More than 20, including Python, JavaScript, TypeScript, Java, Go, C#, Swift, and Kotlin.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Does CodeFactor integrate with Bitbucket as well as GitHub?$q$, $q$Yes, both are supported.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Can CodeFactor automatically fix issues?$q$, $q$Yes, autofix is available for certain issue types, either on demand or automatically.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Is CodeFactor free for students and nonprofits?$q$, $q$Yes, a free Pro plan is offered for verified students and qualifying non-profits.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Who founded CodeFactor?$q$, $q$Darius Kriksciukaitis and Kestas Barzdaitis founded it in 2016.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Public quality badge for open source$q$, $q$An open-source project displays a live quality grade badge for its public repository.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Pull request quality gates$q$, $q$A small dev team enforces quality checks automatically on every pull request.$q$, $q$Small engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Client repository health monitoring$q$, $q$An agency tracks code health across multiple client repositories from one dashboard.$q$, $q$Development agencies and consultancies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Community$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Unlimited public repos","Unlimited users","0 private repos","Quality badge, PR decoration, grade history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Pro$q$, $q$Not publicly listed, billed per private repository$q$, $q$monthly or annual$q$, NULL, $q$["Limited number of private repos","2 branches per repository","2GB max repository size","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$Pro Max$q$, $q$Not publicly listed, billed per private repository$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited private repos","Unlimited branches","Unlimited repository size","Subject to fair use policy","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$how-grading-works$q$, $q$How CodeFactor's A-F Grading Works$q$, 2, ARRAY[$q$CodeFactor's analysis engine checks cyclomatic complexity, cognitive complexity, code duplication, style violations, and common anti-patterns for each supported language, then rolls those findings into a letter grade from A to F.$q$, $q$Grades are shown at the file, directory, and repository level, with a historical chart so teams can track whether quality is trending up or down over time rather than reacting only to individual pull requests.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$pricing-explained$q$, $q$CodeFactor Pricing: Per-Repository, Not Per-Seat$q$, 2, ARRAY[$q$Unlike most code-quality tools, CodeFactor bills by private repository rather than by user. The Community plan is free with unlimited public repos and unlimited users; Pro and Pro Max add private repos at increasing size and branch limits.$q$, $q$Annual billing saves up to 20 percent versus monthly, and students plus qualifying non-profits can get a free Pro plan, with larger non-profits receiving a 20 percent discount.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f94f585b-eadc-4fdf-9b77-2326d9c9c55b', $q$integrations$q$, $q$Supported Languages and Integrations$q$, 2, ARRAY[$q$CodeFactor supports more than 20 languages, including Python, JavaScript, TypeScript, Java, C#, Go, Swift, Kotlin, and Dart, and connects to both GitHub and Bitbucket with zero-configuration setup.$q$, $q$Notifications route into Slack or Microsoft Teams, and CodeFactor can autofix certain reported issues on demand or automatically as part of the review workflow.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Built-in NoSQL document database$q$, $q$RocksDB-based database with a MongoDB-like query language included in every project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Key-value store$q$, $q$A separate lightweight store for simple state alongside the document database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Background job queues$q$, $q$Queues with dedicated workers for asynchronous processing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Cron-scheduled tasks$q$, $q$Scheduled jobs can trigger behind any endpoint without extra infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Webhook handling with retries$q$, $q$Inbound and outbound webhooks with signature verification and automatic retries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Webhook inspector$q$, $q$Captures, inspects, and replays incoming webhook payloads during development.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$JWT and JWKS authentication$q$, $q$Built-in authentication with encrypted API keys to protect endpoints.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$CLI-first fast deploys$q$, $q$Deploys typically complete in under five seconds with no containers or build steps.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Flat-rate pricing means bills do not spike with request volume$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Many backend primitives, including database, queue, cron, and webhooks, are bundled into one platform$q$, 1);
