INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Built by an experienced team with a decade of backend-SaaS history via restdb.io$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Designed to work well with AI coding agents for automated backend generation$q$, 4);
