INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Rate limits on requests per minute are relatively low on entry-level plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Smaller ecosystem and community than Firebase, Supabase, or AWS Lambda$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$No relational or SQL database option; NoSQL only$q$, 3);
