INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$What is codehooks.io?$q$, $q$A serverless JavaScript and TypeScript backend platform with a built-in NoSQL database, queues, cron, and webhooks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Who built codehooks.io?$q$, $q$Codehooks AS, based in Norway, built by the team behind restdb.io.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Is codehooks.io billed per request?$q$, $q$No, it uses flat-rate tiered pricing rather than per-request metering.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$What database does codehooks.io use?$q$, $q$A built-in NoSQL document database on RocksDB with a MongoDB-like query language.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Does codehooks.io support cron jobs?$q$, $q$Yes, cron-scheduled tasks can trigger behind any endpoint.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Can codehooks.io receive and process webhooks?$q$, $q$Yes, with signature verification and automatic retries for inbound and outbound webhooks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Is there a free plan?$q$, $q$Yes, the Development plan is free with limited request-rate and storage quotas.$q$, 6, 'published');
