INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Pro$q$, $q$$19 per month$q$, $q$monthly$q$, NULL, $q$["3600 API requests per minute","15GB database storage","3 developer seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$Team$q$, $q$$99 per month$q$, $q$monthly$q$, NULL, $q$["6000 API requests per minute","25GB database storage","6 developer seats"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$built-in-backend$q$, $q$What Ships Behind Every codehooks.io Endpoint$q$, 2, ARRAY[$q$Every deployed codehooks.io project includes a queryable NoSQL document database built on RocksDB with a MongoDB-like query language, a lightweight key-value store, background job queues with workers, and cron-scheduled tasks.$q$, $q$It also handles inbound and outbound webhooks with signature verification and automatic retries, useful for receiving events from Stripe, Shopify, or GitHub, plus JWT and JWKS authentication and encrypted API keys for protecting endpoints.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$flat-rate-pricing$q$, $q$Flat-Rate Pricing Instead of Per-Request Billing$q$, 2, ARRAY[$q$Unlike most serverless platforms, codehooks.io charges flat monthly rates rather than metering per request or invocation, so a team's bill stays predictable within its plan's rate limits.$q$, $q$Plans scale by API requests per minute, database storage, and developer seats, with a la carte add-ons available for extra developers, storage, custom domains, and dedicated spaces.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77ec0e4-dcb2-4ec6-b1b5-af439818971f', $q$cli-and-agent-workflow$q$, $q$CLI-First and AI-Agent-Ready Deployment$q$, 2, ARRAY[$q$Developers write handler functions locally and deploy via a terminal command, with deploys typically completing in under five seconds since there are no containers to build.$q$, $q$The platform is designed to be driven by AI coding agents such as Claude Code or Cursor, and includes a webhook inspector for capturing and replaying payloads during development.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Folder and label organization$q$, $q$Snippets can be grouped into folders or tagged with labels for fast retrieval.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Filterable snippet library$q$, $q$Users filter their saved snippets by label to find code quickly.$q$, 1);
