INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$What is CodeKeep?$q$, $q$A code snippet manager for saving, organizing, and sharing reusable code and text.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$How much does CodeKeep cost?$q$, $q$A free tier is available; paid plans start at 4.99 US dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Does CodeKeep have a VSCode extension?$q$, $q$Yes, plus a Google Chrome extension for web-based capture.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Can I organize snippets into folders in CodeKeep?$q$, $q$Yes, via folders and labels, with filtering by label.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Does CodeKeep let me share snippets as images?$q$, $q$Yes, via its built-in screenshot editor with templates and backgrounds.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Is CodeKeep only for individuals?$q$, $q$It targets both individuals and small to medium-sized teams.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Where is CodeKeep based?$q$, $q$Not publicly disclosed.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Can other users discover snippets I share publicly?$q$, $q$Yes, CodeKeep includes a public snippet discovery feature.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Reusing boilerplate code$q$, $q$A developer saves and reuses boilerplate and utility code across multiple projects.$q$, $q$Individual developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Sharing styled code for tutorials$q$, $q$A technical writer or educator shares styled code images for tutorials or social posts.$q$, $q$Content creators and educators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Shared team snippet library$q$, $q$A small team maintains a shared, searchable internal snippet library.$q$, $q$Small development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Free$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Basic snippet storage and organization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$Paid plan$q$, $q$Starting at $4.99 per month$q$, $q$monthly$q$, NULL, $q$["Expanded storage and organization","Extension access","Screenshot sharing"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$organization-and-capture$q$, $q$How Snippet Organization and Capture Work$q$, 2, ARRAY[$q$CodeKeep organizes snippets using folders and labels, letting users filter their library by label to quickly relocate a piece of code they saved earlier, the core capture-and-reuse workflow the product is built around.$q$, $q$A Visual Studio Code extension and a Google Chrome extension reduce copy-paste friction, letting users pull snippets directly into an editor or push editor code into the CodeKeep library without leaving their existing workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$screenshot-sharing$q$, $q$Turning Snippets Into Shareable Images$q$, 2, ARRAY[$q$A built-in screenshot editor turns any saved snippet into a styled, shareable image, with templates, backgrounds, and image treatments for use in documentation, presentations, or social posts.$q$, $q$The platform also includes a public discovery feature where users can browse snippets other members have chosen to share, adding a community dimension on top of private organization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ce09b99-f2be-46e5-87e9-b738add6bd0c', $q$pricing-and-availability$q$, $q$Pricing and What Is Not Publicly Disclosed$q$, 2, ARRAY[$q$CodeKeep uses a freemium model: a free tier covers basic personal use, and paid plans start at 4.99 US dollars per month for expanded capacity.$q$, $q$The company does not publish its founding year, headquarters, or team size on its main marketing pages; those details should be treated as not publicly disclosed.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Native support for Flutter, React Native, iOS, and Android$q$, $q$One platform covers cross-platform and native mobile stacks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Visual workflow editor and YAML config$q$, $q$Pipelines can be built visually or defined in a codemagic.yaml file.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$macOS, Linux, and Windows build machines$q$, $q$Includes Mac mini M2 and M4 machines for iOS builds.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Automated code signing$q$, $q$Handles iOS and Android code signing and app store submission automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Parallel and concurrent builds$q$, $q$Supports running multiple builds simultaneously depending on plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$React Native CodePush$q$, $q$Separately priced over-the-air update distribution for React Native apps.$q$, 5);
