INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Pay-as-you-go costs can become unpredictable for high-frequency build teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$CodePush pricing is a separate line item from core CI/CD pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$What platforms does Codemagic support?$q$, $q$Flutter, React Native, native iOS, and native Android.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Who owns Codemagic?$q$, $q$It is developed by Nevercode, based in Tartu, Estonia, and has an official partnership with Google.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Is there a free Codemagic plan?$q$, $q$Yes, 500 macOS M2 build minutes per month with one parallel build and one team member.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$How is Codemagic priced?$q$, $q$Free, pay-as-you-go per build minute, fixed annual plans, or custom Enterprise pricing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Does Codemagic support automated iOS code signing?$q$, $q$Yes, code signing and app store submission are automated.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$What is Codemagic CodePush?$q$, $q$A separately priced over-the-air update service for React Native apps.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Can I use Codemagic without owning a Mac?$q$, $q$Yes, it provides macOS build machines in the cloud for iOS builds.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Does Codemagic offer SSO for enterprise teams?$q$, $q$Yes, OpenID, OAuth2, and SAML 2.0 are available on the Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Flutter build and release automation$q$, $q$A Flutter team automates cross-platform builds and app store releases.$q$, $q$Flutter development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$React Native over-the-air updates$q$, $q$A React Native team distributes updates instantly via CodePush without app store review.$q$, $q$React Native teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Native mobile CI replacement$q$, $q$A native iOS or Android team replaces manual Xcode or Gradle builds with automated CI.$q$, $q$Native mobile engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["500 macOS M2 build minutes per month","1 parallel build","1 team member","30-day build history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Pay as You Go$q$, $q$$0 base, per-minute billing$q$, $q$usage-based$q$, NULL, $q$["$0.095/min Mac mini M2","$0.114/min Mac mini M4","$0.045/min Linux and Windows","Unlimited team members","60-day artifact storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Fixed Price (M2, M4, M4 Max)$q$, $q$$3990 to $9000 per year$q$, $q$annual$q$, NULL, $q$["3 concurrent builds","Unlimited build minutes","1-year build history"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$Enterprise$q$, $q$Starting at $12000 per year$q$, $q$annual$q$, NULL, $q$["Custom features","Dedicated support","SSO (OpenID, OAuth2, SAML 2.0)","Signed SLAs, NDAs, and DPAs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$company-history$q$, $q$From a 2012 Hackathon to Google's Flutter Partner$q$, 2, ARRAY[$q$Codemagic traces to a 2012 internal hackathon at Mobi Lab in Tartu, Estonia, which produced Greenhouse, released as a product in 2014 and rebranded to Nevercode in 2017.$q$, $q$In December 2018, Nevercode launched Codemagic as the first CI/CD tool built exclusively for Flutter, and later formed an official partnership with Google that positions Codemagic as a recommended Flutter CI/CD tool, while Nevercode continues to operate it independently.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$how-codemagic-works$q$, $q$Build Pipelines, Code Signing, and Store Delivery$q$, 2, ARRAY[$q$Teams connect a mobile repository and define pipelines via a visual editor or a codemagic.yaml file, running builds, tests, code signing, and store submissions across macOS, Linux, and Windows machines.$q$, $q$Because iOS builds require macOS hardware, pricing is largely organized around which Mac machine tier, M2 or M4, a build runs on, with results delivered automatically to testers or app store review queues.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe10ef49-8462-4ceb-b099-a81501193e11', $q$pricing-breakdown$q$, $q$Pay-as-You-Go, Fixed, and Enterprise Pricing$q$, 2, ARRAY[$q$Pay-as-you-go bills per build minute, from 0.045 dollars on Linux or Windows up to 0.114 dollars on Mac mini M4, while Fixed Price plans offer unlimited build minutes for a flat annual fee starting at 3,990 dollars.$q$, $q$Enterprise pricing starts at 12,000 dollars per year and adds SSO, dedicated support, and signed SLAs, NDAs, and DPAs, while a separate CodePush pricing track covers React Native over-the-air updates.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Single Java/Kotlin codebase for multiple platforms$q$, $q$Targets iOS, Android, desktop, and web from one codebase.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Cloud build servers$q$, $q$Produce native iOS binaries without requiring a Mac, from Windows or Linux.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Device simulator$q$, $q$Test applications locally before running a native cloud build.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Visual theme and UI builder$q$, $q$Design tools for building and customizing app interfaces.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Native SDK access$q$, $q$Java and Kotlin code can call native platform SDK capabilities directly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$IDE integrations$q$, $q$Works with common Java development environments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$In-app commerce validation$q$, $q$Validates in-app purchases up to plan-specific monthly limits.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Scaled push notifications$q$, $q$Delivers push notifications at volumes that scale with the paid plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Core framework is fully open source with no royalties or per-app fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Cloud build service enables native iOS builds from Windows or Linux$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Long track record dating to 2012, with roots in Sun Microsystems' LWUIT$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Lets existing Java and Kotlin teams reach mobile without learning new languages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Tiered pricing scales from a free evaluation tier to enterprise support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Java and Kotlin UI paradigm is less mainstream for mobile today than Swift, Kotlin-native, or Flutter and Dart$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Smaller community and hiring pool than Flutter or React Native$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Company headquarters and team size are not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Free tier's build-credit limits make it unsuitable for active development$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Native look-and-feel parity requires more manual theming than some modern frameworks$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$What languages does Codename One use?$q$, $q$Java and Kotlin.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Is Codename One free?$q$, $q$The core framework is open source and free; the optional cloud build service has paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Can I build iOS apps on Windows or Linux with Codename One?$q$, $q$Yes, via its cloud build service, without owning a Mac.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Who created Codename One?$q$, $q$Chen Fishbein and Shai Almog, in 2012.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$What platforms does Codename One target?$q$, $q$iOS, Android, desktop, web, and other device categories.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Does Codename One charge royalties on commercial apps?$q$, $q$No, there are no royalties or per-app fees.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$What is included in the Free cloud build plan?$q$, $q$100 build credits per month, with an 8.5MB user JAR size limit.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Is there a money-back guarantee on paid plans?$q$, $q$Yes, a 30-day money-back guarantee applies to paid plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Enterprise Java mobile expansion$q$, $q$An enterprise Java team extends an existing codebase to mobile platforms.$q$, $q$Enterprise Java developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$iOS builds without a Mac$q$, $q$A Windows or Linux-based developer produces native iOS builds via cloud build servers.$q$, $q$Windows and Linux-based mobile developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Single codebase across platforms$q$, $q$A small team builds one codebase targeting iOS, Android, and desktop simultaneously.$q$, $q$Small mobile development teams and indie studios$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["100 build credits per month","8 credits per iOS cloud build","8.5MB JAR limit","No royalties for commercial apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Basic$q$, $q$$25 per month ($300 per year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited build credits","Native platform sources","50MB JAR limit","5000 push notifications per month","5 automated submissions per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Pro$q$, $q$$85 per month ($1020 per year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Concurrent cloud builds","Crash protection with GitHub Issues","1 million push notifications per month","Email support","Native desktop apps"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$Enterprise$q$, $q$$450 per month ($5400 per year annual)$q$, $q$monthly or annual$q$, NULL, $q$["High-priority builds and CI","On-device unit tests","10 million push notifications per month","Phone support","Unlimited automated submissions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$history-and-origins$q$, $q$From Sun Microsystems LWUIT to Codename One$q$, 2, ARRAY[$q$Codename One was founded in January 2012 by Chen Fishbein and Shai Almog, former Sun Microsystems engineers who in 2007 created the Lightweight User Interface Toolkit to simplify Java ME mobile development.$q$, $q$After leaving Oracle, the pair built Codename One as an independent, free alternative to proprietary cross-platform tools, and its 2012 beta release quickly passed 100,000 SDK downloads.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$how-it-works$q$, $q$Write Once, Run Anywhere: The Technical Model$q$, 2, ARRAY[$q$Codename One combines a portable application runtime and UI toolkit with native compilers, per-platform ports, and direct access to native SDK capabilities, letting one Java or Kotlin codebase target iOS, Android, desktop, web, and more.$q$, $q$Its cloud build servers compile Java bytecode into native iOS binaries, letting developers on Windows or Linux build native iOS apps without owning a Mac.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ae5dbe6-de96-475d-8fa3-f54dcfab7a61', $q$cloud-build-pricing$q$, $q$Free Framework, Paid Cloud Build Tiers$q$, 2, ARRAY[$q$The core framework is free, open source, and carries no royalties or per-app fees for commercial or non-commercial use.$q$, $q$The optional cloud build service is priced per developer seat across Free, Basic, Pro, and Enterprise tiers, scaling build credits, push notification volume, submission automation, and support level.$q$]::text[], 2);
